function maxNumberOfCopies(s, target) {
    let sCounts = new Array(26).fill(0);
    let targetCounts = new Array(26).fill(0);

    for (let c of s)
        sCounts[c.charCodeAt(0) - 'a'.charCodeAt(0)]++;

    for (let c of target)
        targetCounts[c.charCodeAt(0) - 'a'.charCodeAt(0)]++;

    let maxCopies = Number.MAX_SAFE_INTEGER;
    for (let i = 0; i < 26; i++) {
        if (targetCounts[i] > 0)
            maxCopies = Math.min(maxCopies, Math.floor(sCounts[i] / targetCounts[i]));
    }
    return maxCopies;
}
```


